package nftables

import (
	"encoding/json"
	"testing"
)

func TestStringSetElementsUnmarshal(t *testing.T) {
	data := []byte(`{
		"nftables": [
			{
				"set": {
					"family": "inet",
					"name": "AllowedIPs",
					"table": "firewall",
					"type": "ipv4_addr",
					"handle": 18,
					"flags": ["interval"],
					"elem": ["10.47.55.250", "10.47.56.232"]
				}
			}
		]
	}`)

