		t.Fatalf("unmarshal failed: %v", err)
	}
	if len(nftable.Sets) != 1 {
		t.Fatalf("got %d sets, want 1", len(nftable.Sets))
	}
	if got := len(nftable.Sets[0].Elem); got != 2 {
		t.Fatalf("got %d elems, want 2", got)
	}
}
GOEOF
(
	cd "$work" || exit 1
	go mod init repro.example/nftables >/dev/null 2>&1
	go test -run TestStringSetElementsUnmarshal -count=1
)
